ps.pstext:
if !HaveSVE2FP8FMA() then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(Zda);

CheckFPMREnabled();
if IsFeatureImplemented(FEAT_SSVE_FP8FMA) && IsFeatureImplemented(FEAT_FP8FMA) then
    CheckSVEEnabled();
elsif IsFeatureImplemented(FEAT_FP8FMA) then
    CheckNonStreamingSVEEnabled();
else
    CheckStreamingSVEEnabled();
end;
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV 16;
let operand1 : bits(VL) = Z{}(n);
let operand2 : bits(VL) = Z{}(m);
let operand3 : bits(VL) = Z{}(da);
var result : bits(VL);

for e = 0 to elements-1 do
    let element1 : bits(8) = operand1[(2 * e + 1)*:8];
    let element2 : bits(8) = operand2[(2 * e + 1)*:8];
    let element3 : bits(16) = operand3[e*:16];
    result[e*:16] = FP8MulAddFP{16}(element3, element1, element2, FPCR(), FPMR());
end;

Z{VL}(da) = result;
